	if host == "" {
		return fmt.Errorf("URL must have a hostname")
	}

	// Check for localhost variations
	localhostVariants := []string{"localhost", "localhost.localdomain"}
	for _, variant := range localhostVariants {
		if strings.EqualFold(host, variant) {
			return fmt.Errorf("access to localhost is not allowed")
		}
	}

	// Check if host is an IP address
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
		return nil
	}

	// Resolve hostname and check all IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %v", err)
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("hostname resolves to private IP address")
		}
	}

	return nil
}

// safeDialer creates a dialer that validates resolved IPs
func safeDialer(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Resolve the address
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	// Check all resolved IPs
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("connection to private IP address blocked")
		}
	}

	// Use the first valid IP
	var dialer net.Dialer
	return dialer.Dial("tcp", net.JoinHostPort(ips[0].String(), port))
