func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetBodyString(`{"success":false,"error":"Method not allowed"}`)
		return
	}

	// Parse JSON request body
	var req URLPreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetBodyString(`{"success":false,"error":"Invalid JSON"}`)
		return
	}

	// Validate URL
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetBodyString(`{"success":false,"error":"URL is required"}`)
		return
	}

	// Create HTTP client with DialDualStack
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Create request
	httpReq := fasthttp.AcquireRequest()
	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(httpReq)
	defer fasthttp.ReleaseResponse(httpResp)

	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)

	// Fetch URL with DoRedirects and 3 second timeout
	err := doWithTimeout(func() error {
		return client.DoRedirects(httpReq, httpResp, 5)
	}, 3*time.Second)

	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		resp := URLPreviewResponse{
			Success: false,
			Error:   err.Error(),
		}
		ctx.SetBodyString(mustMarshalJSON(resp))
		return
	}

	// Parse HTML to extract title and meta description
	title, description := parseHTML(httpResp.Body())

	// Prepare response
	resp := URLPreviewResponse{
		Title:       title,
		Description: description,
		Success:     true,
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetBodyString(mustMarshalJSON(resp))
}

func doWithTimeout(fn func() error, timeout time.Duration) error {
	done := make(chan error, 1)
	go func() {
		done <- fn()
	}()

	select {
	case err := <-done:
		return err
	case <-time.After(timeout):
		return fasthttp.ErrTimeout
	}
}

func parseHTML(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
