					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if strings.Contains(name, "description") {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return title, description
}

