// secureDial validates the resolved IP address before allowing connection
// This prevents SSRF attacks by blocking connections to private/internal IPs
func secureDial(addr string) (net.Conn, error) {
	// Dial the connection first
	conn, err := fasthttp.DialDualStack(addr)
	if err != nil {
		return nil, err
	}

	// Get the remote address and validate the IP
	remoteAddr := conn.RemoteAddr()
	if tcpAddr, ok := remoteAddr.(*net.TCPAddr); ok {
		remoteIP := tcpAddr.IP
		if !isSafeIP(remoteIP) {
