// validateURL performs additional URL validation to prevent SSRF
func validateURL(u *url.URL) error {
	host := u.Hostname()
	if host == "" {
		return fmt.Errorf("URL must have a hostname")
	}

	// Check for IP addresses directly in URL
	if ip := net.ParseIP(host); ip != nil {
		if !isSafeIP(ip) {
			return fmt.Errorf("connection to %s is not allowed", host)
		}
	}

	return nil
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var titleFound, descriptionFound bool

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if titleFound && descriptionFound {
			return
		}

		if n.Type == html.ElementNode {
			// Extract title from <title> tag
			if n.Data == "title" && !titleFound {
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
					titleFound = true
				}
			}

			// Extract meta description from <meta name="description"> tag
			if n.Data == "meta" && !descriptionFound {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name != "" && content != "" {
					description = strings.TrimSpace(content)
					descriptionFound = true
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description, nil
}

