		ctx.SetContentType("application/json")
		response := PreviewResponse{
			Success: false,
			Error:   fmt.Sprintf("Invalid URL: %v", err),
		}
		jsonResponse, _ := json.Marshal(response)
		ctx.SetBody(jsonResponse)
		return
	}

	// Fetch the URL content
	resp := &fasthttp.Response{}
	reqFast := &fasthttp.Request{}
	reqFast.SetRequestURI(req.URL)
	reqFast.Header.SetMethod("GET")
	reqFast.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreview/1.0)")

	if err := client.DoRedirects(reqFast, resp, 3); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		response := PreviewResponse{
			Success: false,
			Error:   fmt.Sprintf("Failed to fetch URL: %v", err),
		}
		jsonResponse, _ := json.Marshal(response)
		ctx.SetBody(jsonResponse)
		return
	}

