import (
	"bytes"
	"encoding/json"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// RequestPayload defines the expected JSON body structure
type RequestPayload struct {
	URL string `json:"url"`
}

// ResponsePayload defines the JSON response structure
type ResponsePayload struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles the POST request to fetch URL preview
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set response content type to JSON
	ctx.SetContentType("application/json")

	// Parse the JSON body
	var reqPayload RequestPayload
	if err := json.Unmarshal(ctx.PostBody(), &reqPayload); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		body, _ := json.Marshal(ResponsePayload{Error: "Invalid JSON body"})
		ctx.SetBody(body)
		return
	}

	// Validate URL presence
	if reqPayload.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		body, _ := json.Marshal(ResponsePayload{Error: "URL is required"})
		ctx.SetBody(body)
		return
	}

	// Configure fasthttp Client
	client := &fasthttp.Client{
		Dial:       fasthttp.DialDualStack,
		ReadTimeout: 3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	// Acquire request and response objects
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	// Set request details
	req.SetRequestURI(reqPayload.URL)
	req.Header.SetMethod(fasthttp.MethodGet)

	// Fetch the URL content following redirects
	// Using DoRedirects as required by constraints
	err := client.DoRedirects(req, resp, 10)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		body, _ := json.Marshal(ResponsePayload{Error: err.Error()})
		ctx.SetBody(body)
		return
	}

	// Parse HTML to extract title and meta description
	title, description := parseHTML(resp.Body())

	// Prepare successful response
	ctx.SetStatusCode(fasthttp.StatusOK)
	respPayload := ResponsePayload{
		Title:       title,
		Description: description,
	}
	body, _ := json.Marshal(respPayload)
	ctx.SetBody(body)
}

// parseHTML extracts the title and meta description from HTML content
func parseHTML(body []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return "", ""
	}

	var title, description string
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}
			// Extract Meta Description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name != "" {
					description = strings.TrimSpace(content)
				}
			}
		}
		// Traverse children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)
	return title, description
}

func main() {
	// Start the server on port 8080
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		panic(err)
	}
}

