import (
	"encoding/json"
	"fmt"
	"log"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// URLPreviewRequest represents the incoming request body
type URLPreviewRequest struct {
	URL string `json:"url"`
}

// URLPreviewResponse represents the response body
type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Success     bool   `json:"success"`
	Error       string `json:"error,omitempty"`
}

// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for IPv4 mapped to IPv6
	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 127.0.0.0/8
		if ip4[0] == 127 {
			return true
		}
		// 0.0.0.0
		if ip4[0] == 0 {
			return true
		}
		// 224.0.0.0/4 (multicast)
		if ip4[0] >= 224 && ip4[0] <= 239 {
			return true
		}
		// 240.0.0.0/4 (reserved)
		if ip4[0] >= 240 {
			return true
		}
	}

	return false
}

// validateURL checks if the URL is safe to fetch
func validateURL(rawURL string) error {
	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL format")
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("only http and https schemes are allowed")
	}

	host := parsedURL.Hostname()
	if host == "" {
		return fmt.Errorf("hostname is required")
	}

	// Check if host is an IP address
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
	}

	return nil
}

// Global fasthttp client with required Dial setting
var client = &fasthttp.Client{
	Dial: func(addr string) (net.Conn, error) {
		host, port, err := net.SplitHostPort(addr)
		if err != nil {
			return nil, err
		}

		// Resolve the hostname to IP addresses
		ips, err := net.LookupIP(host)
		if err != nil {
			return nil, err
		}

		// Check if any of the resolved IPs are private/internal
		for _, ip := range ips {
			if isPrivateIP(ip) {
				return nil, fmt.Errorf("access to private IP addresses is not allowed")
			}
		}

		// Use standard dialer with timeout
		dialer := &net.Dialer{
			Timeout:   5 * time.Second,
			KeepAlive: 30 * time.Second,
		}
		return dialer.Dial("tcp", net.JoinHostPort(host, port))
	},
	ReadTimeout:  10 * time.Second,
	WriteTimeout: 10 * time.Second,
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"success":false,"error":"Method not allowed"}`)
		return
	}

	// Parse JSON request body
	var req URLPreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"success":false,"error":"Invalid JSON"}`)
		return
	}

	// Validate URL
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"success":false,"error":"URL is required"}`)
		return
	}

	// Validate URL scheme and host
	if err := validateURL(req.URL); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"success":false,"error":"` + err.Error() + `"}`)
		return
	}

	// Fetch the URL content
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	req_fasthttp := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req_fasthttp)

	req_fasthttp.SetRequestURI(req.URL)
	req_fasthttp.Header.SetMethod(fasthttp.MethodGet)
	req_fasthttp.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Use DoRedirects to follow redirects (required by specification)
	if err := client.DoRedirects(req_fasthttp, resp, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"success":false,"error":"` + err.Error() + `"}`)
		return
	}

	// Check response status
	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"success":false,"error":"Failed to fetch URL"}`)
		return
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(resp.Body())

	// Build response
	response := URLPreviewResponse{
		Title:       title,
		Description: description,
		Success:     true,
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	jsonResp, _ := json.Marshal(response)
	ctx.SetBody(jsonResp)
}

func parseHTML(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var titleFound, descFound bool
	var f func(*html.Node)
	f = func(n *html.Node) {
		if titleFound && descFound {
			return
		}

		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && !titleFound {
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
					titleFound = true
				}
			}

			// Extract meta description
			if n.Data == "meta" && !descFound {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name != "" && content != "" {
					description = strings.TrimSpace(content)
					descFound = true
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return title, description
}

func main() {
	log.Println("Starting server on :8080")
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

