	"golang.org/x/net/html"
)

// PreviewRequest represents the incoming request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the response body
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Success     bool   `json:"success"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch URL preview information
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse request body
	var req PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.Write([]byte(`{"success":false,"error":"Invalid JSON body"}`))
		return
	}

	// Validate URL
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.Write([]byte(`{"success":false,"error":"URL is required"}`))
		return
	}

	// Create HTTP client with Dial set to DialDualStack
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Create request
	fasthttpReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(fasthttpReq)
	fasthttpReq.SetRequestURI(req.URL)
	fasthttpReq.Header.SetMethod(fasthttp.MethodGet)

	// Create response
	fasthttpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(fasthttpResp)

	// Fetch with timeout using goroutine and channel
	done := make(chan error, 1)
	go func() {
		done <- client.DoRedirects(fasthttpReq, fasthttpResp, 3)
	}()

	select {
	case err := <-done:
		if err != nil {
			ctx.SetStatusCode(fasthttp.StatusBadGateway)
			ctx.SetContentType("application/json")
			ctx.Write([]byte(fmt.Sprintf(`{"success":false,"error":"%s"}`, err.Error())))
			return
		}
	case <-time.After(3 * time.Second):
		ctx.SetStatusCode(fasthttp.StatusGatewayTimeout)
		ctx.SetContentType("application/json")
		ctx.Write([]byte(`{"success":false,"error":"Request timeout"}`))
		return
	}

	// Parse HTML to extract title and meta description
	title, description := parseHTML(fasthttpResp.Body())

	// Prepare response
	response := PreviewResponse{
		Title:       title,
		Description: description,
		Success:     true,
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	jsonResp, _ := json.Marshal(response)
	ctx.Write(jsonResp)
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(body []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var title, description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name != "" && content != "" {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return title, description
}

func main() {
	fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

