// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip net.IP) bool {
	// Check for localhost
	if ip.IsLoopback() {
		return true
	}

	// Check for link-local unicast
	if ip.IsLinkLocalUnicast() {
		return true
	}

	// Check for private IP ranges (IPv4)
	if ip.To4() != nil {
		ip4 := ip.To4()
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 127.0.0.0/8
		if ip4[0] == 127 {
			return true
		}
		// 169.254.0.0/16 (link-local)
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		// 0.0.0.0
		if ip4[0] == 0 {
			return true
		}
	}

	// Check for IPv6 loopback
	if ip.IsLoopback() {
		return true
	}

	return false
}

// validateURL checks if the URL is safe to fetch
func validateURL(rawURL string) (*url.URL, error) {
	// Parse the URL
	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return nil, fmt.Errorf("invalid URL format")
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, fmt.Errorf("only http and https schemes are allowed")
	}

	// Check if host is present
	if parsedURL.Host == "" {
		return nil, fmt.Errorf("URL host is required")
	}

	// Extract hostname (remove port if present)
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return nil, fmt.Errorf("URL hostname is required")
	}

	// Resolve hostname to IP addresses
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve hostname")
	}

	// Check each IP address
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private IP addresses is not allowed")
		}
	}

	return parsedURL, nil
}

// safeDial creates a safe dialer that validates IP addresses
func safeDial(addr string) (net.Conn, error) {
	// Extract host from addr (host:port format)
	host, _, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Resolve the host
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	// Check each IP address
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private IP addresses is not allowed")
		}
	}

	// Use standard dialer with timeout
	dialer := &net.Dialer{
		Timeout: 10 * time.Second,
	}
	return dialer.Dial("tcp", addr)
}

