	_, err := validateURL(req.URL)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		response := URLPreviewResponse{
			Success: false,
			Error:   err.Error(),
		}
		body, _ := json.Marshal(response)
		ctx.SetBody(body)
		return
	}

	// Create request and response objects
	fasthttpReq := &fasthttp.Request{}
	fasthttpResp := &fasthttp.Response{}

	// Set up the request
	fasthttpReq.SetRequestURI(req.URL)
	fasthttpReq.Header.SetMethod("GET")
	fasthttpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Use DoRedirects to fetch the URL with redirect handling
	if err := client.DoRedirects(fasthttpReq, fasthttpResp, 5); err != nil {
