		body, _ := json.Marshal(response)
		ctx.SetBody(body)
		return
	}

	// Check status code
	if fasthttpResp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		response := URLPreviewResponse{
			Success: false,
			Error:   fmt.Sprintf("Failed to fetch URL: status code %d", fasthttpResp.StatusCode()),
		}
		body, _ := json.Marshal(response)
		ctx.SetBody(body)
		return
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(fasthttpResp.Body())

	// Build successful response
	response := URLPreviewResponse{
		Title:       title,
		Description: description,
		Success:     true,
	}

	body, err := json.Marshal(response)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetBodyString(`{"success": false, "error": "Failed to marshal response"}`)
		return
	}

	ctx.SetBody(body)
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title from <title> tag
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract description from <meta name="description"> tag
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name != "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		// Recursively traverse child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return
}

