}

// validateURL validates the URL to prevent SSRF attacks
func validateURL(rawURL string) error {
	u, err := url.Parse(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL: %v", err)
	}

	// Only allow http and https schemes
	if u.Scheme != "http" && u.Scheme != "https" {
		return fmt.Errorf("only http and https schemes are allowed")
	}

	// Check if host is present
	if u.Host == "" {
		return fmt.Errorf("URL host is required")
	}

	// Resolve the host to check IP addresses
	host := u.Hostname()
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("failed to resolve host: %v", err)
	}

	// Check all resolved IPs
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private/internal IP addresses is not allowed")
		}
	}

	return nil
}

// Global HTTP client with required configuration
var client = &fasthttp.Client{
	Dial: func(addr string) (net.Conn, error) {
		// Extract host and port from addr
		host, _, err := net.SplitHostPort(addr)
		if err != nil {
			return nil, err
		}

		// Resolve and validate IP
		ips, err := net.LookupIP(host)
		if err != nil {
			return nil, err
		}

		// Check all resolved IPs
		for _, ip := range ips {
			if isPrivateIP(ip) {
				return nil, fmt.Errorf("access to private/internal IP addresses is not allowed")
			}
		}

		return fasthttp.DialDualStack(addr)
	},
	ReadTimeout:  10 * time.Second,
	WriteTimeout: 10 * time.Second,
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if string(ctx.Method()) != "POST" {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON body
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL
	if reqBody.URL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Security validation to prevent SSRF
	if err := validateURL(reqBody.URL); err != nil {
		ctx.Error(fmt.Sprintf("URL validation failed: %v", err), fasthttp.StatusBadRequest)
		return
	}

	// Fetch the URL content
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod("GET")
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreview/1.0)")

	// Fetch with redirects support using DoRedirects
	if err := client.DoRedirects(req, resp, 10); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Check content type
	contentType := string(resp.Header.ContentType())
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.Error("URL does not return HTML content", fasthttp.StatusUnsupportedMediaType)
		return
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(resp.Body())

	// Build response
	response := PreviewResponse{
		Title:       title,
		Description: description,
		URL:         reqBody.URL,
	}

	// Send JSON response
	responseBody, err := json.Marshal(response)
	if err != nil {
		ctx.Error("Failed to marshal response", fasthttp.StatusInternalServerError)
		return
	}

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetBody(responseBody)
}

func parseHTML(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content, property string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						name = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					case "property":
						property = strings.ToLower(attr.Val)
					}
				}
				if name == "description" || property == "og:description" {
					description = strings.TrimSpace(content)
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return
}

func main() {
	fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

