)

// Request body structure
type URLPreviewRequest struct {
	URL string `json:"url"`
}

// Response body structure
type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	URL         string `json:"url"`
}

// Global HTTP client with configured settings
var client = &fasthttp.Client{
	Dial:        fasthttp.DialDualStack,
	ReadTimeout: 3 * time.Second,
	WriteTimeout: 3 * time.Second,
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"error":"Method not allowed"}`)
		return
	}

	// Parse JSON request body
	var req URLPreviewRequest
	if err := json.Unmarshal(ctx.Request.Body(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"error":"Invalid JSON body"}`)
		return
	}

	// Validate URL
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"error":"URL is required"}`)
		return
	}

	// Create request to fetch the URL
	request := fasthttp.AcquireRequest()
	response := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(request)
	defer fasthttp.ReleaseResponse(response)

	request.SetRequestURI(req.URL)
	request.Header.SetMethod(fasthttp.MethodGet)

	// Fetch with 3 second timeout using DoRedirects
	err := client.DoRedirects(request, response, 3)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(fmt.Sprintf(`{"error":"Failed to fetch URL: %s"}`, err.Error()))
		return
	}

	// Check response status
	if response.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(fmt.Sprintf(`{"error":"Failed to fetch URL: status %d"}`, response.StatusCode()))
		return
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(response.Body())

	// Build response
	resp := URLPreviewResponse{
		Title:       title,
		Description: description,
		URL:         req.URL,
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	respBody, _ := json.Marshal(resp)
	ctx.SetBody(respBody)
}

func parseHTML(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name != "" && content != "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return title, description
}

func main() {
	// Start server
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		fmt.Printf("Error starting server: %s\n", err)
	}
}

