// FetchURLPreview handles POST requests to fetch URL preview data
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON request body
	var req URLPreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL
	if req.URL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Create HTTP client with Dial set to DialDualStack
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Acquire request and response objects
	request := fasthttp.AcquireRequest()
	response := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(request)
	defer fasthttp.ReleaseResponse(response)

	// Set up the request
	request.SetRequestURI(req.URL)
	request.Header.SetMethod(fasthttp.MethodGet)

	// Use DoRedirects to fetch the URL with redirect following
	// Implement 3-second timeout using goroutine and channel
	done := make(chan error, 1)
	go func() {
		done <- client.DoRedirects(request, response, 3)
	}()

	select {
	case err := <-done:
		if err != nil {
			ctx.Error("Failed to fetch URL: "+err.Error(), fasthttp.StatusBadGateway)
			return
		}
	case <-time.After(3 * time.Second):
		ctx.Error("Request timeout", fasthttp.StatusGatewayTimeout)
		return
	}

	// Check content type
	contentType := string(response.Header.ContentType())
	if !strings.Contains(contentType, "text/html") {
		ctx.Error("URL does not return HTML content", fasthttp.StatusUnsupportedMediaType)
		return
	}

	// Parse HTML to extract title and meta description
	title, description := parseHTML(response.Body())

	// Create response object
	resp := URLPreviewResponse{
		Title:       title,
		Description: description,
		URL:         req.URL,
	}

	// Set response headers and write JSON response
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	jsonData, err := json.Marshal(resp)
	if err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
	ctx.Write(jsonData)
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name != "" && content != "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	// Start the HTTP server on port 8080
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		panic(err)
	}
}

