	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

type URLPreviewRequest struct {
	URL string `json:"url"`
}

type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Success     bool   `json:"success"`
	Error       string `json:"error,omitempty"`
}

var client = &fasthttp.Client{
	Dial: func(addr string) (net.Conn, error) {
		return fasthttp.DialDualStack(addr)
	},
	ReadTimeout:  5 * time.Second,
	WriteTimeout: 5 * time.Second,
}

// validateURL checks if the URL is safe to fetch (prevents SSRF)
func validateURL(rawURL string) error {
	if rawURL == "" {
		return fmt.Errorf("URL is required")
	}

	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL: %v", err)
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("only http and https schemes are allowed")
	}

	host := parsedURL.Hostname()
	if host == "" {
		return fmt.Errorf("invalid URL: missing host")
	}

	// Resolve the hostname to check IP addresses
	ipAddrs, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %v", err)
	}

	// Check if any resolved IP is private/internal
	for _, ip := range ipAddrs {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to internal/private IP addresses is not allowed")
		}
	}

	return nil
}

// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	if ip.IsPrivate() {
		return true
	}

	// Check for IPv4 private ranges
	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 127.0.0.0/8 (loopback)
		if ip4[0] == 127 {
			return true
		}
		// 0.0.0.0
		if ip4[0] == 0 {
			return true
		}
	}

	return false
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if string(ctx.Method()) != "POST" {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON request body
	var req URLPreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")

		resp := URLPreviewResponse{
			Success: false,
			Error:   "Invalid JSON body",
		}
		body, _ := json.Marshal(resp)
		ctx.SetBody(body)
		return
	}

	// Validate URL (including SSRF protection)
	if err := validateURL(req.URL); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")

		resp := URLPreviewResponse{
			Success: false,
			Error:   err.Error(),
		}
		body, _ := json.Marshal(resp)
		ctx.SetBody(body)
		return
	}

	// Fetch the URL content
	resp := &fasthttp.Response{}
	req_fasthttp := &fasthttp.Request{}
	req_fasthttp.SetRequestURI(req.URL)
	req_fasthttp.Header.SetMethod("GET")
	req_fasthttp.Header.Set("User-Agent", "Mozilla/5.0")

	if err := client.DoRedirects(req_fasthttp, resp, 5); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")

		response := URLPreviewResponse{
			Success: false,
			Error:   fmt.Sprintf("Failed to fetch URL: %v", err),
		}
		body, _ := json.Marshal(response)
		ctx.SetBody(body)
		return
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(resp.Body())

	// Return response
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")

	response := URLPreviewResponse{
		Title:       title,
		Description: description,
		Success:     true,
	}
	body, _ := json.Marshal(response)
	ctx.SetBody(body)
}

func parseHTML(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return title, description
}

func main() {
	fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

