		ctx.SetBodyString(fmt.Sprintf("Failed to fetch URL: %v", err))
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetBodyString(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()))
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetBodyString("Empty response body")
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetBodyString(fmt.Sprintf("Failed to parse HTML: %v", err))
		return
	}

