	if err := validateURL(req.URL); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		response := Response{Error: fmt.Sprintf("Invalid URL: %v", err)}
		writeJSONResponse(ctx, response)
		return
	}

	// Create HTTP client with custom dialer and timeout
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			// Extract host from addr
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			// Resolve and check IP
			ips, err := net.LookupIP(host)
			if err != nil {
				return nil, err
			}

			for _, ip := range ips {
				if isPrivateIP(ip) {
					return nil, fmt.Errorf("access to private IP addresses is not allowed")
				}
			}

			return fasthttp.DialDualStack(addr)
		},
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
	}

