	fasthttpReq := fasthttp.AcquireRequest()
	fasthttpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(fasthttpReq)
	defer fasthttp.ReleaseResponse(fasthttpResp)

	fasthttpReq.SetRequestURI(req.URL)
	fasthttpReq.Header.SetMethod("GET")
	fasthttpReq.Header.Set("User-Agent", "Mozilla/5.0")

	// Fetch the URL with redirects
	if err := client.DoRedirects(fasthttpReq, fasthttpResp, 5); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		response := Response{Error: fmt.Sprintf("Failed to fetch URL: %v", err)}
		writeJSONResponse(ctx, response)
