)

// PreviewRequest defines the expected JSON body structure
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the JSON response structure
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles the POST request to fetch URL preview data
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Ensure only POST requests are processed
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetContentType("application/json")
		ctx.Write([]byte(`{"error":"method not allowed"}`))
		return
	}

	// Parse JSON body
	var req PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.Write([]byte(`{"error":"invalid json body"}`))
		return
	}

	// Validate URL presence
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		ctx.Write([]byte(`{"error":"url field is required"}`))
		return
	}

	// Configure fasthttp Client according to requirements
	client := &fasthttp.Client{
		// MUST set fasthttp.Client.Dial to fasthttp.DialDualStack
		Dial: fasthttp.DialDualStack,
		// MUST set timeout to 3 seconds
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	// Acquire request and response objects
	request := fasthttp.AcquireRequest()
	response := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(request)
	defer fasthttp.ReleaseResponse(response)

	// Setup request
	request.SetRequestURI(req.URL)
	request.Header.SetMethod(fasthttp.MethodGet)
	request.Header.SetUserAgent("Mozilla/5.0 (compatible; Go URL Preview Bot)")

	// MUST use fasthttp.Client.DoRedirects method to fetch the provided URL
	// Allow up to 5 redirects
	err := client.DoRedirects(request, response, 5)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		respBody, _ := json.Marshal(PreviewResponse{Error: err.Error()})
		ctx.Write(respBody)
		return
	}

	// Parse HTML content to extract title and meta description
	doc, err := html.Parse(bytes.NewReader(response.Body()))
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetContentType("application/json")
		respBody, _ := json.Marshal(PreviewResponse{Error: "failed to parse html content"})
		ctx.Write(respBody)
		return
	}

	title, description := extractMetadata(doc)

	result := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	respBody, _ := json.Marshal(result)
	ctx.Write(respBody)
}

// extractMetadata traverses the HTML node tree to find title and description
func extractMetadata(n *html.Node) (string, string) {
	var title, description string
	var walker func(*html.Node)

	walker = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract Meta Description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = strings.TrimSpace(content)
				}
			}
		}

		// Traverse children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walker(c)
		}
	}

	walker(n)
	return title, description
}

func main() {
	fmt.Println("Starting server on :8080...")
	// Start the fasthttp server
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		fmt.Printf("Error starting server: %s\n", err)
	}
}

