	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			ctx.SetStatusCode(fasthttp.StatusBadRequest)
			ctx.SetContentType("application/json; charset=utf-8")
			ctx.SetBodyString(`{"error":"Access to private IP address is not allowed"}`)
			return
		}
