	fasthttpReq := fasthttp.AcquireRequest()
	fasthttpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(fasthttpReq)
	defer fasthttp.ReleaseResponse(fasthttpResp)

	fasthttpReq.SetRequestURI(req.URL)
	fasthttpReq.Header.SetMethod(fasthttp.MethodGet)

	// Fetch with redirects and 3 second timeout
	err := httpClient.DoRedirects(fasthttpReq, fasthttpResp, 10)
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(fasthttpResp.Body())

