	response := URLPreviewResponse{
		Title:       title,
		Description: description,
		URL:         req.URL,
	}

	// Set response headers
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)

	// Write JSON response
	jsonResp, err := json.Marshal(response)
	if err != nil {
		ctx.Error("Failed to marshal response", fasthttp.StatusInternalServerError)
		return
	}

	ctx.Write(jsonResp)
}

func parseHTML(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var titleFound, descFound bool

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if titleFound && descFound {
			return
		}

		if n.Type == html.ElementNode {
			// Extract title from <title> tag
			if n.Data == "title" && !titleFound {
