		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(fmt.Sprintf(`{"success":false,"error":"HTTP status: %d"}`, resp.StatusCode()))
		return
	}

	// Check content type
	contentType := string(resp.Header.ContentType())
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetContentType("application/json")
		ctx.SetBodyString(`{"success":false,"error":"Content is not HTML"}`)
		return
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(resp.Body())

	// Build response
	response := URLPreviewResponse{
		Title:       title,
		Description: description,
		Success:     true,
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	jsonBytes, _ := json.Marshal(response)
	ctx.SetBody(jsonBytes)
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name != "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return title, description
}

func main() {
	// Start server on port 8080
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

